unitsize (5 cm);

path[] cantor;
int n;

cantor[0] = (1/3,1/2)--(2/3,1/2);

for (n = 1; n <= 10; ++n) {
  cantor[n] = yscale(1/2)*xscale(1/3)*(cantor[n - 1])--cantor[0]--shift((2/3,1/2))*yscale(1/2)*xscale(1/3)*(cantor[n - 1]);
}

draw(cantor[10],red);
draw((0,0)--(1,0));
draw((0,0)--(0,1));
[/asy]

